// Change this IP address to your phone IP shown in Phyphox Remote Access.
// Use a Phyphox experiment that exposes accX, accY, accZ, gyrX, gyrY, gyrZ.
const PHONE_IP = "192.168.1.50";
msg.url = `http://${PHONE_IP}:8080/get?accX&accY&accZ&gyrX&gyrY&gyrZ`;
return msg;

// 3D rigid-body orientation engine using accelerometer + gyroscope
// Complementary filter: gyro gives fast response; accelerometer corrects roll/pitch drift.
// Units assumed: accelerometer in m/s^2, gyroscope in rad/s.

function latest(bufferObj) {
    if (!bufferObj || !bufferObj.buffer || bufferObj.buffer.length === 0) return 0;
    return Number(bufferObj.buffer[bufferObj.buffer.length - 1]);
}

const b = msg.payload.buffer || {};
let ax = latest(b.accX);
let ay = latest(b.accY);
let az = latest(b.accZ);
let gx = latest(b.gyrX);
let gy = latest(b.gyrY);
let gz = latest(b.gyrZ);

// Noise threshold for gyro
if (Math.abs(gx) < 0.005) gx = 0;
if (Math.abs(gy) < 0.005) gy = 0;
if (Math.abs(gz) < 0.005) gz = 0;

let s = context.get("orientationState") || {
    roll: 0,
    pitch: 0,
    yaw: 0,
    lastTime: Date.now()
};

let now = Date.now();
let dt = (now - s.lastTime) / 1000.0;
s.lastTime = now;
if (dt <= 0 || dt > 1.0) dt = 0.1;

// Integrate gyroscope
let rollGyro = s.roll + gx * dt;
let pitchGyro = s.pitch + gy * dt;
let yawGyro = s.yaw + gz * dt;

// Accelerometer-based roll and pitch
let rollAcc = Math.atan2(ay, az);
let pitchAcc = Math.atan2(-ax, Math.sqrt(ay * ay + az * az));

// Complementary filter
const alpha = 0.98;
s.roll = alpha * rollGyro + (1 - alpha) * rollAcc;
s.pitch = alpha * pitchGyro + (1 - alpha) * pitchAcc;
s.yaw = yawGyro; // yaw cannot be corrected by accelerometer alone

context.set("orientationState", s);

const rad2deg = 180 / Math.PI;
let omegaMag = Math.sqrt(gx*gx + gy*gy + gz*gz);
let accMag = Math.sqrt(ax*ax + ay*ay + az*az);

let motionState = "STABLE";
if (omegaMag > 1.0) motionState = "FAST ROTATION";
else if (omegaMag > 0.1) motionState = "SLOW ROTATION";

msg.payload = {
    ax, ay, az,
    gx, gy, gz,
    accMag,
    omegaMag,
    roll: s.roll,
    pitch: s.pitch,
    yaw: s.yaw,
    rollDeg: s.roll * rad2deg,
    pitchDeg: s.pitch * rad2deg,
    yawDeg: s.yaw * rad2deg,
    state: motionState,
    dt
};
return msg;

context.set("orientationState", {
    roll: 0,
    pitch: 0,
    yaw: 0,
    lastTime: Date.now()
});
msg.payload = {
    ax: 0, ay: 0, az: 0,
    gx: 0, gy: 0, gz: 0,
    accMag: 0,
    omegaMag: 0,
    roll: 0,
    pitch: 0,
    yaw: 0,
    rollDeg: 0,
    pitchDeg: 0,
    yawDeg: 0,
    state: "RESET",
    dt: 0
};
return msg;
